/// This is the integer div/rem simplification driver.
/// It tries to simplify signed and unsigned divisions and remainders.
static Value *simplifyDivRem(BinaryOperator *I, InstCombiner::BuilderTy &Builder) {
  Value *Op0 = I->getOperand(0), *Op1 = I->getOperand(1);

  // The simple cases are handled by the instruction simplify logic.
  if (auto *C = dyn_cast<ConstantInt>(Op1)) {
    if (I->getOpcode() == Instruction::UDiv)
      if (Value *V = simplifyUDiv(Op0, C, I->getModule()->getDataLayout()))
        return V;
    if (I->getOpcode() == Instruction::SDiv)
      if (Value *V = simplifySDiv(Op0, C, I->getModule()->getDataLayout()))
        return V;
    if (I->getOpcode() == Instruction::URem)
      if (Value *V = simplifyURem(Op0, C, I->getModule()->getDataLayout()))
        return V;
    if (I->getOpcode() == Instruction::SRem)
      if (Value *V = simplifySRem(Op0, C, I->getModule()->getDataLayout()))
        return V;
  }

  return nullptr;
}

/// This is a utility for simplifyValueKnownNonZero.
/// It is used to determine if we can simplify a udiv/sdiv/urem/srem by a
/// non-zero value.
static bool isKnownNonZeroInCttz(Value *V, const DataLayout &DL,
                                 unsigned Depth, AssumptionCache *AC,
                                 Instruction *CxtI) {
  // It is trivial to determine if the value is non-zero.
  if (isKnownNonZero(V, DL, Depth, AC, CxtI))
    return true;

  // The value is non-zero if the number of trailing zeros is less than the
  // bitwidth.
  KnownBits Known = computeKnownBits(V, DL, Depth, AC, CxtI);
  return Known.countMinTrailingZeros() < Known.getBitWidth();
}

